-- Birlestirme (CONCAT)
SELECT CONCAT(name, ' - ', email) AS student_info
FROM students;

-- Buyuk/kucuk harf
SELECT UPPER(name) AS upper_name, LOWER(name) AS lower_name
FROM students;

-- Uzunluk
SELECT name, LENGTH(name) AS name_length
FROM students;

-- Alt metin alma (SUBSTRING)
SELECT name, SUBSTRING(name, 1, 3) AS short_name
FROM students;

-- TRIM ile bosluk temizleme
SELECT TRIM('  Merhaba  ') AS trimmed;

-- REPLACE ile degistirme
SELECT REPLACE(email, '@example.com', '@school.edu') AS new_email
FROM students;

-- CONCAT_WS ile ayraçli birlestirme
SELECT CONCAT_WS(' | ', name, email, age) AS combined
FROM students;

-- Isim soyisim ayirma (LOCATE ve SUBSTRING ile)
SELECT
    name,
    SUBSTRING(name, 1, LOCATE(' ', name) - 1) AS first_name,
    SUBSTRING(name, LOCATE(' ', name) + 1) AS last_name
FROM students;
